CREATE TABLE `article_paragraphs` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '段落唯一ID',
  `article_id` int unsigned NOT NULL COMMENT '文章ID',
  `paragraph_number` int unsigned NOT NULL COMMENT '段落序号（如1/2/3，每篇文章内唯一）',
  `content` text NOT NULL COMMENT '段落原文（完整文本）',
  `translation` text COMMENT '段落译文（完整文本）',
  `sentence_list` json NOT NULL COMMENT '段落拆分后的句子数组（后端预处理，如["句1","句2"]）',
  `sentence_translation_list` json DEFAULT NULL COMMENT '句子对应的译文数组（可选）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_flag` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_article_paragraph` (`article_id`,`paragraph_number`) COMMENT '每篇文章的段落序号唯一',
  UNIQUE KEY `UKbst44whscpunntot6bh7lsgcm` (`article_id`,`paragraph_number`),
  KEY `idx_article_id` (`article_id`) COMMENT '按文章ID查所有段落的核心索引',
  CONSTRAINT `article_paragraphs_ibfk_1` FOREIGN KEY (`article_id`) REFERENCES `articles` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='文章分段内容表（含句子数组）';
