  `question_type_id` int unsigned NOT NULL COMMENT '题型ID（关联question_types表）',
  `stem` text NOT NULL COMMENT '题干内容',
  `options` json DEFAULT (json_array()) COMMENT '选项数组（如[{"label":"A","content":"选项A"},...]，单选/多选有值，填空/判断为空）',
  `correct_answer` json NOT NULL COMMENT '正确答案（适配不同题型：单选存"A"，多选存["A","C"]，判断存"True"）',
  `analysis` text COMMENT '题目解析内容（TEXT字段去掉DEFAULT ''）',
  `answer_paragraph_number` int unsigned NOT NULL COMMENT '答案句所在段落序号',
  `answer_sentence_index` int unsigned NOT NULL COMMENT '答案句在段落sentence_list中的索引',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
