  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_article_question` (`article_id`,`question_number`) COMMENT '每篇文章的题号唯一',
  UNIQUE KEY `UKf7btvlswc6458080ehgawtell` (`article_id`,`question_number`),
  KEY `idx_article_id` (`article_id`) COMMENT '按文章ID查所有题目',
  KEY `idx_question_type_id` (`question_type_id`) COMMENT '按题型筛选题目',
  CONSTRAINT `questions_ibfk_1` FOREIGN KEY (`article_id`) REFERENCES `articles` (`id`) ON DELETE CASCADE,
  CONSTRAINT `questions_ibfk_2` FOREIGN KEY (`question_type_id`) REFERENCES `question_types` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=41 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='雅思阅读题目表';
