/*!40000 ALTER TABLE `questions` DISABLE KEYS */;
INSERT INTO `questions` VALUES (1,1,1,4,'There are other parrots that share the kakapo\'s inability to fly.','[{\"label\": \"TRUE\"}, {\"label\": \"FALSE\"}, {\"label\": \"NOT GIVEN\"}]','\"FALSE\"','解题思路：文章第一段明确指出，鸮鹦鹉（kākāpō）是“世界上唯一不会飞的鹦鹉”（the world\'s only flightless parrot）。原文中“only”这一排他性的限定词与题干中“share ... inability to fly”（暗示其他鸟类也共有此特征）的信息直接冲突，因此判断为FALSE。\r\n 对应文章：第1段：It is the world\'s only flightless parrot,\r\n 避坑：在做判断题时，要特别留意“only”、“all”、“every”等绝对化词汇。原文中的“only”具有唯一性，如果题目试图打破这种唯一性，通常就是错误的。不要凭常识猜测是否存在其他不会飞的鸟类，必须严格依据文中对“鹦鹉”这一特定类别的描述。',2,3,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(2,1,2,4,'Adult kakapo produce chicks every year.','[{\"label\": \"TRUE\"}, {\"label\": \"FALSE\"}, {\"label\": \"NOT GIVEN\"}]','\"FALSE\"','解题思路：由题目中的 produce chicks 定位到文章第3段第1句，对应文中的 breed。文中指出鸮鹦鹉虽然在夏秋季节繁殖，但有一个关键的前提条件：“仅在食物充足的年份”（only in years when food is plentiful）。题目中使用的“every year”（每年）属于频率上的绝对化表述，忽略了文中提到的食物供应这一限制性因素，两者信息矛盾，故选FALSE。\r\n 对应文章：第3段：Kakapo breed in summer and autumn, but only in years when food is plentiful.\r\n 避坑：注意区分“经常发生”与“必然发生”。雅思阅读中，频率副词（如every, always, usually）是常见的考点。如果原文对某种行为设定了触发条件（如食物充足），那么该行为就不是无条件每年发生的，不能将“有条件发生”等同于“定期发生”。',4,0,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(3,1,3,4,'Adult male kakapo bring food back to nesting females.','[{\"label\": \"TRUE\"}, {\"label\": \"FALSE\"}, {\"label\": \"NOT GIVEN\"}]','\"FALSE\"','解题思路：紧接着上一题定位处，文章第三段第二句明确指出雄性鸮鹦鹉“不参与孵卵或育雏”（Males play no part in incubation or chick-rearing），且“喂养雏鸟由雌性独自完成”（females alone... feed the chicks）。这与题干中“成年雄性鸮鹦鹉会带食物回来”（adult male kakapo bring food back）的信息直接相悖，因此是FALSE。\r\n 避坑：考生容易受到其他鸟类习性的干扰，认为雄性带回食物是常理。但在阅读理解中，必须以文本为准。看到“alone”或“no part”这类词时，应立即警觉题目中关于分工协作的描述是否属实，不要带入主观经验。',4,1,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(4,1,4,4,'The Polynesian rat was a greater threat to the kakapo than Polynesian settlers.','[{\"label\": \"TRUE\"}, {\"label\": \"FALSE\"}, {\"label\": \"NOT GIVEN\"}]','\"NOT GIVEN\"','解题思路：文章第四段提到波利尼西亚定居者及其带来的波利尼西亚鼠（Polynesian rat）都会捕食鸮鹦鹉。虽然文中确认两者均构成威胁，但并未对二者的威胁程度进行高低或大小的比较（文中未出现类似 greater than 的比较级）。由于原文仅陈述了两个事实而缺乏横向对比，无法判断谁的威胁更大，该信息在文中属于未知，故选 NOT GIVEN。\r\n 避坑：这是典型的“无端比较”陷阱。当题目中出现比较级（如 greater, more than）时，必须在原文中寻找对应的比较关系。如果原文只是分别陈述事实而没有进行对比，则结论不可知，不能主观推断某种威胁更大。',5,4,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(5,1,5,4,'Kakapo were transferred from Rakiura Island to other locations because they were at risk from feral cats.','[{\"label\": \"TRUE\"}, {\"label\": \"FALSE\"}, {\"label\": \"NOT GIVEN\"}]','\"TRUE\"','解题思路：根据 feral cats 和 Rakiura 定位到文中第七段。开头提到拉奇乌拉岛（Rakiura Island）上的野猫捕食导致鸮鹦鹉数量迅速下降，紧接着用“As a result”（结果是）引出应对措施：幸存的种群被“疏散”（evacuated）到了三个岛屿保护区。这里的“evacuated to three...”对应题干中的“were transferred from ... to other ...”，信息完全匹配，故选TRUE。\r\n 对应文章：Unfortunately, predation by feral cats on Rakiura Island led to a rapid decline in kakapo numbers. As a result, during 1980-97, the surviving population was evacuated to three island sanctuaries:\r\n 避坑：解题时要关注因果逻辑词。文中“As a result”明确了“野猫威胁”与“迁移行动”之间的因果关系。此外，要具备同义替换的意识，理解“evacuated to... sanctuaries”本质上就是一种为了避开风险而进行的“transfer”。',8,0,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(6,1,6,4,'One Recovery Plan initiative that helped increase the kakapo population size was caring for struggling young birds.','[{\"label\": \"TRUE\"}, {\"label\": \"FALSE\"}, {\"label\": \"NOT GIVEN\"}]','\"TRUE\"','解题思路：文章中描述了1996年启动的新“复兴计划”（Recovery Plan）的具体措施，其中明确提到包括“营救并人工抚养任何衰弱的雏鸟”（rescuing and hand-raising any failing chicks）。题目中的“caring for struggling young birds”是文中“hand-raising failing chicks”的同义转述，且文中随后提到种群数量因此开始增加，信息一致，故选TRUE。\r\n 对应文章：This involved moving the birds between islands, supplementary feeding of adults and rescuing and hand-raising any failing chicks.\r\n 避坑：注意词汇的灵活替换。题目中的“struggling”对应文中的“failing”（指发育不良或生存困难的），“young birds”对应“chicks”。在确认细节时，要确保题目中的措施确实属于“Recovery Plan”的一部分，并且该措施与“增加种群数量”的目标是一致的。',9,4,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(7,1,7,3,'diet consists of fern fronds, various parts of a tree and ___','[]','\"bulbs\"','解题思路：根据题干中的 diet, fern fronds 以及 parts of a tree 定位到文章第二段最后一句。文中提到 kākāpō 的食物包括树叶、根、树皮（对应 parts of a tree）以及 fern fronds（蕨类植物叶子），其中并列提到的另一个成分是 bulbs（球茎）。因此，bulbs 即为答案词。\r\n 对应文章：with their diet including the leaves, roots and bark of trees as well as bulbs, and fern fronds.\r\n 避坑：注意题目要求填入“一个单词和/或一个数字”。在寻找并列关系时，要准确识别出哪些是属于“树的一部分”，哪些是独立提到的植物部位，避免将 bark 或 roots 填入，因为它们已经包含在“parts of a tree”的范畴内。',3,3,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(8,1,8,3,'nests are created in ___ where eggs are laid.','[]','\"soil\"','解题思路：根据题干中的 eggs 定位到文章第三段。文中第3句提到“The 1-4 eggs are laid in soil”，明确指出蛋是产在土壤里的，随后提到土壤在孵化前后会被反复翻动，这与题干中描述的产卵位置一致，因此 soil 为答案词。\r\n 避坑：不要被文中提到的“incubation”（孵化）或“chick-rearing”（育雏）干扰，题目问的是产卵的具体位置。同时注意拼写，确保从原文原词摘录，不要将 soil 误写为 ground。',4,2,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(9,1,9,3,'the ___ of the kākāpō were used to make clothes.','[]','\"feathers\"','解题思路：根据题干中的 Polynesian settlers 和 clothes 定位到文章第四段。文中提到早期定居者捕食 kākāpō，并使用其 feathers（羽毛）来制作 soft cloaks（柔软的斗篷）。这里的 cloaks 对应题干中的 clothes，因此 feathers 即为答案词。\r\n 对应文章：They ate its meat and used its feathers to make soft cloaks.\r\n 避坑：注意题干中的 clothes 是对文中 cloaks 的同义替换。考生需要识别出这种对应关系，并准确提取出制作材料 feathers，不要误填为 meat，因为肉是用来吃的，不是用来做衣服的。',5,3,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(10,1,10,3,'___ were an animal which they introduced that ate the kākāpō\'s food sources.','[]','\"deer\"','解题思路：根据题干中的 European colonisers 和 food sources 定位到文章第四段。文中提到欧洲殖民者引入了多种物种，其中 deer（鹿）消耗了森林中剩余的食物（depleted the remaining forests of food），导致 kākāpō 的食物减少，因此答案词为 deer。\r\n 避坑：文中提到了多种引入物种，如 cats, stoats, rats 等，但这些主要是捕食者（predators）。只有 deer 被明确提及是抢夺食物资源（depleted... food）的物种，需仔细区分物种对 kākāpō 的不同威胁方式。',5,7,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(11,1,11,3,'a definite sighting of female kākāpō on Rakiura Island was reported in the year ___','[]','\"1980\"','解题思路：根据题干中的 female kākāpō 和 Rakiura 定位到文章第六段。由 a definite sighting of female kakapo（对应文中 confirmed females）定位到该段倒数第2句，文中提到 1977 年在 Rakiura 发现了一群雄性，随后在 1980 年确认了雌性（females）也存在。这标志着首次在该岛明确观察到雌性，因此 1980 即为答案词。\r\n 避坑：文中出现了多个年份（1974, 1977, 1980），1977 年只是发现了大量雄性，直到 1980 年才确认有雌性存在。必须准确对应“first definite sighting of female”这一关键信息点，避免混淆年份。',7,5,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(12,1,12,3,'the Recovery Plan included an increase in ___','[]','\"funding\"','解题思路：根据题干中的 1996 Recovery Plan 定位到文章第八段。文中提到 1996 年启动了新的恢复计划，伴随着专家咨询小组的成立以及“a higher amount of funding”（更高额度的资金）。题干中的 increase 对应文中的 higher amount of，因此 funding 即为答案词。\r\n 对应文章：In 1996, a new Recovery Plan was launched, together with a specialist advisory group called the Kakapo Scientific and Technical Advisory Committee and a higher amount of funding.\r\n 避坑：题目要求填入一个单词。虽然文中提到了 specialist advisory group，但题干空格前有 increase in，修饰的是不可数名词或抽象概念，funding（资金）在语境和语法上最为匹配，不要填入冗长的短语。',9,0,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(13,1,13,3,'a current goal of the Recovery Plan is to maintain the involvement of ___ in kākāpō protection.','[]','\"stakeholders\"','解题思路：根据题干中的 current goals 和 involvement 定位到文章最后一段。文中末段叙述了 today（对应题干 current）的情况，列出了恢复计划的关键目标，其中之一是“ensure stakeholders continue to be fully engaged in the preservation of the species”。这里的 continue 对应题干中的 maintain，be fully engaged in 对应 involvement，由此可知 stakeholders 即为答案词。\r\n 避坑：注意识别同义替换。题干中的 involvement（参与）对应文中的 be fully engaged in。此外，要确保单词拼写正确，直接从原文复制 stakeholders，不要漏掉末尾的复数形式 s。',11,1,'2026-03-17 22:18:53','2026-03-17 22:18:53',0),(14,2,14,5,'reference to the research problems that arise from there being only a few surviving large elms','[{\"label\": \"A\"}, {\"label\": \"B\"}, {\"label\": \"C\"}, {\"label\": \"D\"}, {\"label\": \"E\"}, {\"label\": \"F\"}, {\"label\": \"G\"}]','\"C\"','解题思路：本题要求寻找关于“少量幸存的大型榆树给研究带来的挑战”的信息。在文中C部分第2段中，Karen Russell提到需要通过研究那些幸存下来的成熟树木来找出它们未被感染的原因，但紧接着指出“opportunities are limited as the number of these mature survivors is relatively small”（由于这些成熟幸存者的数量相对较少，研究机会是有限的），这直接对应了题干中提到的研究样本稀缺带来的局限性，因此答案为C。\r\n 对应文章：C部分：Nevertheless, opportunities are limited as the number of these mature survivors is relatively small.\r\n 避坑：考生可能会在A段看到关于榆树大量死亡、景观消失的描述而误选A，但A段侧重于描述疾病造成的宏观影响和历史对比，并没有提到在开展科学研究时遇到的具体困难或幸存样本量不足的问题。',3,5,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(15,2,15,5,'details of a difference of opinion about the value of reintroducing elms to Britain','[{\"label\": \"A\"}, {\"label\": \"B\"}, {\"label\": \"C\"}, {\"label\": \"D\"}, {\"label\": \"E\"}, {\"label\": \"F\"}, {\"label\": \"G\"}]','\"G\"','解题思路：题干要求定位“关于重新引入榆树价值的不同观点”。在文章G段中，Karen Russell从环境角度出发，认为重新引入榆树能为野生动物提供栖息地，价值巨大；而Matt Elliot则持谨慎（wary）态度，认为使用非本土杂交品种相当于“克隆”，且存在引入新疾病的风险。这种赞同与警惕的正反观点对比，明确体现了对重新引入榆树价值的不同意见，故答案为G。\r\n 避坑：注意不要因为F段提到了培育抗病品种的技术过程就误选F。F段侧重于“如何”通过科学手段实现重新引入，而G段才真正深入探讨了“是否应该”这样做以及这样做在社会和生态层面的价值争议。',7,3,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(16,2,16,5,'reference to how Dutch elm disease was brought into Britain','[{\"label\": \"A\"}, {\"label\": \"B\"}, {\"label\": \"C\"}, {\"label\": \"D\"}, {\"label\": \"E\"}, {\"label\": \"F\"}, {\"label\": \"G\"}]','\"B\"','解题思路：题干是“荷兰榆树疾病是如何被带入英国的”，文中B部分详述了这种流行病通过运输如何带入英国，答案是B。本题关注疾病进入英国的具体路径。B段详细描述了20世纪70年代的第二次疫情是由“shipments of elm from Canada”（从加拿大运来的榆树货物）触发的。文中进一步解释了这些木材是以造船原木的形式进入的，其完整的树皮为携带致命真菌的甲虫提供了完美的生存环境，从而清晰地揭示了疾病是如何被带入英国的。\r\n 对应文章：B部分：but in the \'70s a second epidemic was triggered by shipments of elm from Canada. The wood came in the form of logs destined for boat building and its intact bark was perfect for the elm bark beetles that spread the deadly fungus. This time, the beetles carried a much more virulent strain that destroyed the vast majority of British elms.。\r\n 避坑：虽然A段提到了疾病导致英国90%的榆树死亡这一结果，但并未涉及疾病的来源。考生需要区分“疾病造成的后果”与“疾病引入的渠道”，后者是B段的核心信息。',2,1,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(17,2,17,5,'a description of the conditions that have enabled a location in Britain to escape Dutch elm disease','[{\"label\": \"A\"}, {\"label\": \"B\"}, {\"label\": \"C\"}, {\"label\": \"D\"}, {\"label\": \"E\"}, {\"label\": \"F\"}, {\"label\": \"G\"}]','\"E\"','解题思路：题干要求寻找“使英国某地逃脱疾病的特定条件”。文中E段详述了布莱顿市（Brighton）约17,000棵榆树的存活要素，指出“Local factors appear to have contributed to their survival. Strong winds from the sea...”（当地因素有助于它们的生存，来自大海的强风使甲虫难以发起攻击）。这明确指出了特定的地理和气候条件对该地区榆树的保护作用，故答案为E。\r\n 避坑：C段虽然也提到了剑桥郡（Cambridgeshire）有幸存的古树，但文中明确说它们是“mysteriously escaped”（神秘地逃脱），即原因尚不明确。而E段给出了布莱顿幸存的具体科学解释（强风），因此E段才是正确匹配项。',5,5,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(18,2,18,5,'reference to the stage at which young elms become vulnerable to Dutch elm disease','[{\"label\": \"A\"}, {\"label\": \"B\"}, {\"label\": \"C\"}, {\"label\": \"D\"}, {\"label\": \"E\"}, {\"label\": \"F\"}, {\"label\": \"G\"}]','\"C\"','解题思路：本题寻找“榆树在哪个生长阶段容易受感染”的信息。文中C段指出，虽然篱笆中存活着数百万小榆树，但它们一旦达到一定尺寸就会成为甲虫的目标。文中给出了具体的物理标准：“Once the trunk of the elm reaches 10-15 centimetres or so in diameter...”（一旦树干直径达到10-15厘米左右），这个阶段的尺寸最适合甲虫产卵和真菌寄生。因此，树干直径在10-15厘米左右是容易感染荷兰榆树病的阶段，对应C段内容。\r\n 避坑：容易误选F段，因为F段提到了对幼苗（seedlings）进行抗病性测试。但F段描述的是人工注射病原体的实验过程，而C段描述的是在自然生长周期中，树木生长到特定粗细（阶段）时才开始面临被甲虫攻击的自然风险。',3,2,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(19,2,19,5,'If a tree gets infected with Dutch elm disease, the damage rapidly becomes visible.','[{\"label\": \"A\"}, {\"label\": \"B\"}, {\"label\": \"C\"}]','\"B\"','解题思路：答案是B。根据文章F段，Karen Russell详细描述了测试新一代树苗抗病性的实验过程。她指出，在向树皮注入病原体后，“效果非常迅速”（The effects are very quick），只需四到六周的时间，那些易感的树木就会表现出落叶症状，甚至可能完全死亡。这一描述直接对应了题干中关于“如果感染，破坏力迅速可见”的论述。\r\n 对应文章：F部分：\'The effects are very quick,\' says Russell. ‘You return in four to six weeks and trees that are resistant show no symptoms, whereas those that are susceptible show leaf loss and may even have died completely.’\r\n 避坑：考生在阅读时需要敏锐捕捉表示时间的词汇，如“four to six weeks”，并将其与“quick”联系起来。同时，要注意区分实验环境下的反应与自然环境下的发病过程，确保定位到Russell关于实验观察的直接引语。',6,3,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(20,2,20,5,'It may be better to wait and see if the mature elms that have survived continue to flourish.','[{\"label\": \"A\"}, {\"label\": \"B\"}, {\"label\": \"C\"}]','\"A\"','解题思路：答案是A。在文章G段末尾，来自林地信托基金会的Matt Elliot表达了对人工干预（如种植杂交品种）的保留意见。他明确提出，“有时你能做的最好的事情就是给自然时间去恢复”（give nature time to recover），并预测随着时间的推移，树木可能会自然产生抗性。这与题干中建议“等待并观察成熟榆树是否能存活并繁茂”的观点完全一致。文章原文为：‘Sometimes the best thing you can do is just give nature time to recover ... over time, you might get resistance,’ says Elliot。\r\n 避坑：容易将此观点与Karen Russell研究幸存树木的科研行为混淆。Russell侧重于主动寻找原因，而Elliot的观点更倾向于“无为而治”的自然恢复策略，考生需通过“give nature time”这一核心短语进行精准匹配。',7,9,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(21,2,21,5,'There must be an explanation for the survival of some mature elms.','[{\"label\": \"A\"}, {\"label\": \"B\"}, {\"label\": \"C\"}]','\"B\"','解题思路：文章C段第2段中，Karen Russell针对在疫情中幸存下来的成熟榆树提出了科学假设。她询问这些树木存活的原因（\'What are the reasons for their survival?\'）是回避、耐受还是抗性，并断言“我不认为这完全取决于运气”（\'I don\'t see how it can be entirely down to luck\'）。这对应了题干中“一定有所解释”（must be an explanation）的说法，即她坚信这些树木的生存存在某种生物学或环境上的合理解释，而非偶然。\r\n 避坑：题干中的“must be an explanation”是对文中否定“luck”的一种反向转述。考生如果只看到Russell在提问而没有读到她对运气说的否定，可能会误以为她也没有答案，从而漏掉这个匹配点。',3,7,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(22,2,22,5,'We need to be aware that insects carrying Dutch elm disease are not very far away.','[{\"label\": \"A\"}, {\"label\": \"B\"}, {\"label\": \"C\"}]','\"C\"','解题思路：答案是C。在E段中，Peter Bourne讨论了布莱顿市榆树面临的持续威胁。他警告说，尽管目前有地理优势保护，但情况依然不稳定，因为“威胁就在我们的家门口”（the threat is right on our doorstep），甲虫随时可能大举入侵。这里的“甲虫”即是携带疾病的昆虫，而“家门口/就在咫尺”则形象地对应了题干中的“非常近”（very close）。\r\n 对应文章：E 部分：‘The beetles can just march in if we\'re not careful, as the threat is right on our doorstep,’ says Bourne.\r\n 避坑：考生需要建立起“beetles”与“insects carrying the disease”之间的逻辑联系。如果在阅读B段时没有记住甲虫是传播媒介这一背景信息，在做此题时可能会因为找不到“insect”这个原词而产生困扰。',5,7,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(23,2,23,5,'You understand the effect Dutch elm disease has had when you see evidence of how prominent the tree once was.','[{\"label\": \"A\"}, {\"label\": \"B\"}, {\"label\": \"C\"}]','\"A\"','解题思路：答案是A。文章A段引用了Matt Elliot的话，他感叹如果没见过当年的景象，很难想象疾病的冲击力。他提到，只有当你查看20世纪60年代的“老照片”（old photographs）时，才会意识到榆树曾经的影响力及其作为“重要且巨大树木”的地位。这里的“老照片”对应题干中提到的“看到证据”（see evidence），证明了榆树曾经的重要性。\r\n 对应文章：A部分：\'The impact of the disease is difficult to picture if you hadn\'t seen what was there before,\' says Matt Elliot of the Woodland Trust. ‘You look at old photographs from the 1960s and it\'s only then that you realise the impact [elms had] ... They were significant, large trees ... then they were gone.’\r\n 避坑：不要被D段中关于榆树在青铜器时代或18世纪用途的描述所干扰。虽然D段也证明了榆树的重要性，但题干强调的是“看到证据”（see evidence），这与Elliot提到的“look at old photographs”这一视觉动作形成了完美的同义替换。',1,5,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(24,2,24,3,'For hundreds of years, the only tree that was more popular in Britain than elm was ___.','[]','\"oak\"','解题思路：文章D段首句提到“elm ran a close second to oak as the hardwood tree of choice in Britain”，意为在长达几个世纪的时间里，榆树作为英国硬木的首选仅次于橡树，位居第二。这说明橡树（oak）是比榆树更受欢迎或更主要的选择，与题干中“more popular”（更广为人知）的描述完全吻合。\r\n 避坑：考生需要准确理解短语“ran a close second to”的含义，它表示“位居第二”或“仅次于”。如果将其误解为“榆树是第一，橡树是第二”，则会无法正确锁定答案。此外，在填写答案时应保持单数形式，与原文一致。',4,0,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(25,2,25,3,'Starting in the Bronze Age, many tools were made from elm and people also used it to make weapons. In the 18th century, it was grown to provide wood for boxes and ___.','[]','\"flooring\"','解题思路：利用题干中的时间关键词“18th century”定位到D段倒数第二句。文中指出，在18世纪，榆木被更广泛地种植，其木材被用于制造“storage crates”和“flooring”。题干中的“boxes”是文中“storage crates”的同义替换，而与之并列的用途即为“flooring”（地板），因此锁定该词为答案。\r\n 对应文章：D部分：In the 18th century, it was planted more widely and its wood was used for items such as storage crates and flooring.\r\n 避坑：在雅思填空题中，题干往往会对原文进行同义改写。考生如果只死找“boxes”这个词而忽略了“storage crates”，可能会漏掉关键信息。同时，务必遵守题目“ONE WORD ONLY”的字数限制，不要写成“the flooring”或复数形式。',4,4,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(26,2,26,3,'Due to its strength, elm was often used for mining equipment and the Cutty Sark\'s ___ was also constructed from elm.','[]','\"keel\"','解题思路：紧接着上一题答案句即提到Cutty Sark，通过专有名词“Cutty Sark”可快速定位至文章D段末句。文中提到榆木适用于承受高强度冲击的物品，并被用于建造19世纪帆船Cutty Sark的“keel”（龙骨）。题干中的“was constructed from”对应文中的“was used to build”，询问的是船的哪个具体部位，由此确定答案为keel。\r\n 对应文章：D部分：It was also suitable for items that experienced high levels of impact and was used to build the keel of the 19th-century sailing ship Cutty Sark as well as mining equipment.\r\n 避坑：部分考生可能不熟悉“keel”这个航海专业词汇，但在阅读考试中，即使不认识单词，只要能通过定位词找到对应的名词结构（the... of the ship）即可得分。注意不要误填“sailing ship”，因为那是船的整体称呼，而非具体部位。',4,5,'2026-03-17 22:46:42','2026-03-17 22:46:42',0),(27,3,27,1,'In the first paragraph, the writer introduces the topic of the text by','[{\"label\": \"A\", \"content\": \"defining some commonly used terms.\"}, {\"label\": \"B\", \"content\": \"questioning a widely held assumption.\"}, {\"label\": \"C\", \"content\": \"mentioning a challenge faced by everyone.\"}, {\"label\": \"D\", \"content\": \"specifying a situation which makes us most anxious.\"}]','\"C\"','解题思路：文章第一段通过描述人们在医疗、财务和职业等重要领域面临决策时感受到压力（stressed and anxious）的状态，指出我们所有人有时都必须在压力下权衡信息。这种普遍面临的困难处境对应了选项C中的“challenge”，作者以此引出全文关于压力如何影响判断的讨论。\r\n 对应文章：第1段整段。\r\n 避坑：不要误选B选项。虽然段末提出了一个问题，但作者并没有质疑某个“广泛持有的假设”，而是通过提问来引导读者思考。同时，选项D提到的“最焦虑的情况”在文中并未界定，文中只是列举了多种压力场景。',1,1,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(28,3,28,1,'What point does the writer make about firefighters in the second paragraph?','[{\"label\": \"A\", \"content\": \"The regular changes of stress levels in their working lives make them ideal study subjects.\"}, {\"label\": \"B\", \"content\": \"The strategies they use to handle stress are of particular interest to researchers.\"}, {\"label\": \"C\", \"content\": \"The stressful nature of their job is typical of many public service professions.\"}, {\"label\": \"D\", \"content\": \"Their personalities make them especially well-suited to working under stress.\"}]','\"A\"','解题思路：题干询问第二段关于消防员（firefighters）的内容。文中描述了消防员工作状态的剧烈波动，从清闲的日常维护到高压的紧急救援。作者指出，这种“起伏（ups and downs）”为观察压力如何改变信息处理能力提供了“完美的实验环境（perfect setting）”。这直接对应了选项A，即消防员工作压力的定期变化（regular changes）使其成为理想的研究对象（ideal study subject）。\r\n 对应文章：第2段：These ups and downs presented the perfect setting for an experiment on how people\'s ability to use information changes when they feel under pressure.\r\n 避坑：注意不要过度推断。虽然文中提到了消防员的工作内容，但并没有说他们的工作是公共服务行业的“典型代表”（选项C），也没有讨论他们的“性格特征”（选项D），重点在于其工作环境对科学实验的价值。',2,4,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(29,3,29,1,'What is the writer doing in the fourth paragraph?','[{\"label\": \"A\", \"content\": \"explaining their findings\"}, {\"label\": \"B\", \"content\": \"justifying their approach\"}, {\"label\": \"C\", \"content\": \"setting out their objectives\"}, {\"label\": \"D\", \"content\": \"describing their methodology\"}]','\"D\"','解题思路：题干问第4段写了什么。在第四段中，作者详细列举了与消防员（firefighters）进行实验的具体步骤：要求受试者估算概率、提供正面或负面信息反馈、再次要求估算。这种对实验过程、步骤和手段的详细记录，在学术写作中属于对“研究方法（methodology）”的描述，故选D。\r\n 避坑：区分“过程”与“结论”。很多考生会误选A（解释发现），但实际上第四段只讲了“怎么做”，而实验得出的“结论”（即压力下人们对坏消息更敏感）是在第五段才开始解释的。',4,1,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(30,3,30,1,'In the seventh paragraph, the writer describes a mechanism in the brain which','[{\"label\": \"A\", \"content\": \"enables people to respond more quickly to stressful situations.\"}, {\"label\": \"B\", \"content\": \"results in increased ability to control our levels of anxiety.\"}, {\"label\": \"C\", \"content\": \"produces heightened sensitivity to indications of external threats.\"}, {\"label\": \"D\", \"content\": \"is activated when there is a need to communicate a sense of danger.\"}]','\"C\"','解题思路：第七段解释了大脑中的一种生理机制。当压力发生时（stressful events），该机制会被触发（is triggered/switch），促使我们关注警告并留意可能出错的地方。脑成像显示：这种\"切换\"关联的是一种神经信号的激增，其对于学习行为至关重要，特别是在面对突发性警示信号如看到人们面露惊恐之时。这对应选项C，即该机制会增强对外部威胁信号的敏感度。\r\n 对应文章：第7段整段。\r\n 避坑：避开选项A的干扰。虽然该机制与压力有关，但文中强调的是对信息的“处理和关注（take in warnings）”，而非反应的“速度（more quickly）”。另外，选项D中的“communicate”意为交流传递，而文中讨论的是大脑内部的接收和处理机制。',7,0,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(31,3,31,5,'At times when they were relaxed, the firefighters usually','[{\"label\": \"A\", \"content\": \"made them feel optimistic.\"}, {\"label\": \"B\", \"content\": \"took relatively little notice of bad news.\"}, {\"label\": \"C\", \"content\": \"responded to negative and positive information in the same way.\"}, {\"label\": \"D\", \"content\": \"were feeling under stress.\"}, {\"label\": \"E\", \"content\": \"put them in a stressful situation.\"}, {\"label\": \"F\", \"content\": \"behaved in a similar manner, regardless of the circumstances.\"}, {\"label\": \"G\", \"content\": \"thought it more likely that they would experience something bad.\"}]','\"B\"','解题思路：根据题干中的关键词“firefighters”和“relaxed”定位至文章第5段。文中明确提到，当消防员处于放松状态时，他们表现得相当乐观，会“忽略坏消息并接受好消息”（ignore bad news and embrace the good）。这说明在放松状态下，他们对负面信息的关注度较低，与选项B“took relatively little notice of bad news”（对坏消息关注相对较少）的描述完全吻合。\r\n 对应文章：第5段：People are normally quite optimistic - they will ignore bad news and embrace the good. This is what happened when the firefighters were relaxed;\r\n 避坑：考生需要准确区分“放松”和“压力”两种对比状态下的不同反应。在放松状态下，人类天生的“乐观偏见”占据主导，因此会下意识地过滤掉负面预测，不要将其与压力状态下对坏消息的警觉反应混淆。',5,0,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(32,3,32,5,'The researchers noted that when the firefighters were stressed, they','[{\"label\": \"A\", \"content\": \"made them feel optimistic.\"}, {\"label\": \"B\", \"content\": \"took relatively little notice of bad news.\"}, {\"label\": \"C\", \"content\": \"responded to negative and positive information in the same way.\"}, {\"label\": \"D\", \"content\": \"were feeling under stress.\"}, {\"label\": \"E\", \"content\": \"put them in a stressful situation.\"}, {\"label\": \"F\", \"content\": \"behaved in a similar manner, regardless of the circumstances.\"}, {\"label\": \"G\", \"content\": \"thought it more likely that they would experience something bad.\"}]','\"G\"','解题思路：定位至第5段。文中提到在压力（under stress）环境下，消防员会对坏消息变得“过度警觉”（hyper-vigilant），即使这些消息与工作无关，他们也会据此“改变自己的信念”（altered their beliefs）。这表明他们不再忽视风险，而是认为自己更可能遭遇坏情况，对应选项G。\r\n 避坑：理解“hyper-vigilant”是解题的关键。它不仅指注意力集中，更隐含了对风险评估的调整。压力作为一种触发机制，使大脑从乐观模式切换到了风险防范模式，从而提高了对负面事件发生概率的预期。',5,2,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(33,3,33,5,'When the firefighters were told good news, they always','[{\"label\": \"A\", \"content\": \"made them feel optimistic.\"}, {\"label\": \"B\", \"content\": \"took relatively little notice of bad news.\"}, {\"label\": \"C\", \"content\": \"responded to negative and positive information in the same way.\"}, {\"label\": \"D\", \"content\": \"were feeling under stress.\"}, {\"label\": \"E\", \"content\": \"put them in a stressful situation.\"}, {\"label\": \"F\", \"content\": \"behaved in a similar manner, regardless of the circumstances.\"}, {\"label\": \"G\", \"content\": \"thought it more likely that they would experience something bad.\"}]','\"F\"','解题思路：紧接着上一题文中定位处，阅读第5段末尾，文中通过“In contrast”引出对比，明确指出“压力并没有改变他们对好消息的反应”（stress didn\'t change how they responded to good news）。这意味着无论消防员是否处于压力之中，他们处理正面信息的方式是保持一致的，即对应选项F“反应方式与放松时相同”。\r\n 对应文章：第5段：In contrast, stress didn\'t change how they responded to good news (such as learning that the likelihood of card fraud was lower than they\'d thought).\r\n 避坑：本题的陷阱在于考生可能会主观推测压力会全方位改变人的认知。但文章强调了这种变化的“选择性”：压力只特异性地增强了对负面信息的吸收，而对正面信息的处理逻辑则保持原样，这种不对称性是实验的核心发现之一。',5,3,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(34,3,34,5,'The students\' cortisol levels and heart rates were affected when the researchers','[{\"label\": \"A\", \"content\": \"made them feel optimistic.\"}, {\"label\": \"B\", \"content\": \"took relatively little notice of bad news.\"}, {\"label\": \"C\", \"content\": \"responded to negative and positive information in the same way.\"}, {\"label\": \"D\", \"content\": \"were feeling under stress.\"}, {\"label\": \"E\", \"content\": \"put them in a stressful situation.\"}, {\"label\": \"F\", \"content\": \"behaved in a similar manner, regardless of the circumstances.\"}, {\"label\": \"G\", \"content\": \"thought it more likely that they would experience something bad.\"}]','\"E\"','解题思路：根据“students”和“public speech”定位至文章第6段。文中描述学生在得知要进行一场会被记录并上传的突击演讲时（即处于stressful situation），生理上出现了剧烈波动，具体表现为“皮质醇水平飙升”和“心率加快”（cortisol levels spiked, their heart rates went up）。这些生理指标的上升正是选项E中提到的“承受压力的身体迹象”（physical signs）。\r\n 对应文章：第6段：in students who were told they had to give a surprise public speech, which would be judged by a panel, recorded and posted online. Sure enough, their cortisol levels spiked, their heart rates went up ...\r\n 避坑：解题时应聚焦于“被告知要演讲”这一瞬间触发的即时反应。虽然文章随后提到了他们处理信息能力的提升，但那是生理反应带来的结果。题干询问的是状态描述，因此最直接、最准确的对应点是文中描述的生理变化。',6,0,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(35,3,35,5,'In both experiments, negative information was processed better when the subjects','[{\"label\": \"A\", \"content\": \"made them feel optimistic.\"}, {\"label\": \"B\", \"content\": \"took relatively little notice of bad news.\"}, {\"label\": \"C\", \"content\": \"responded to negative and positive information in the same way.\"}, {\"label\": \"D\", \"content\": \"were feeling under stress.\"}, {\"label\": \"E\", \"content\": \"put them in a stressful situation.\"}, {\"label\": \"F\", \"content\": \"behaved in a similar manner, regardless of the circumstances.\"}, {\"label\": \"G\", \"content\": \"thought it more likely that they would experience something bad.\"}]','\"D\"','解题思路：文中第3至第7段对以消防员（firefighters）和学生（students）为实验对象的两个实验进行了陈述、分析和总结。作者在第6段首句明确指出在学生身上观察到了“同样的模式”（the same pattern），即在压力状态下，无论是职业消防员还是普通学生，处理负面或警示性信息（alarming information）的能力都会显著增强，这对应了选项D。\r\n 对应文章：第3、4、5、6、7段。\r\n 避坑：本题要求对两个实验对象进行横向总结。考生需要识别出文中“bad news”、“alarming information”与选项中“negative information”的同义替换关系。同时要理解文章的主旨：压力是一种进化而来的机制，旨在提高个体在危险环境中处理威胁信息效率。',7,0,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(36,3,36,4,'The tone of the content we post on social media tends to reflect the nature of the posts in our feeds.','[{\"label\": \"YES\"}, {\"label\": \"NO\"}, {\"label\": \"NOT GIVEN\"}]','\"YES\"','解题思路：根据题干中的关键词 social media 和 feeds 定位到文章第九段最后两句。文中明确指出，如果我们看到社交媒体上的积极动态（如粉色日落的图片），就更有可能发布令人振奋的信息；反之，如果看到负面帖子（如抱怨排长队），则会相应地产生更多负面内容。这说明我们发布内容的基调反映了 feeds 内容的性质，与题干描述完全一致，故判定为 YES。\r\n 对应文章：第9段：Studies show that if we observe positive feeds on social media, such as images of a pink sunset, we are more likely to post uplifting messages ourselves. If we observe negative posts, such as complaints about a long queue at the coffee shop, we will in turn create more negative posts.\r\n 避坑：在做此类题目时，要注意文中提到的“positive feeds”和“negative posts”与题干中“nature of the posts”的对应关系。不要被具体的例子（如日落或排队）干扰，而要抓住其背后的逻辑规律，即社交媒体上情绪和内容的传染性。只要文中逻辑方向与题干一致，即可判定为 YES。',9,3,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(37,3,37,4,'Phones have a greater impact on our stress levels than other electronic media devices.','[{\"label\": \"YES\"}, {\"label\": \"NO\"}, {\"label\": \"NOT GIVEN\"}]','\"NOT GIVEN\"','解题思路：利用关键词 phones 定位到文章第十段第二句。该句提到根据美国心理学会的一项调查，频繁查看手机与压力有关。然而，纵观全文，作者仅讨论了手机使用与压力的相关性，并未将手机对压力水平的影响与其他电子媒体设备（如平板电脑、电脑或电视等）进行对比，也没有提到手机的影响是否“更大”。由于文中缺失横向比较的信息，判定为 NOT GIVEN。\r\n 对应文章：第10段：Repeatedly checking your phone, according to a survey conducted by the American Psychological Association, is related to stress.\r\n 避坑：这是典型的“无中生有”型题目。考生容易根据生活常识认为手机确实比其他设备使用频率更高、带来的压力更大，从而先入为主地误选 YES。在雅思阅读中，必须严格遵循原文，文中缺失横向比较的信息，因此只能判定为 NOT GIVEN。',10,1,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(38,3,38,4,'The more we read about a stressful public event on social media, the less able we are to take the information in.','[{\"label\": \"YES\"}, {\"label\": \"NO\"}, {\"label\": \"NOT GIVEN\"}]','\"NO\"','解题思路：根据题干 stressful public event 定位至第十一段。文中指出，在经历此类压力事件后，个人会变得“非常关注”（become very aware of）媒体上的警示信息，且压力会暂时“增加”（enhances）人们吸收负面报告的可能性。这与题干中“越读越无法吸收信息”（less able to take the information in）的描述完全相反，故判断为 NO。\r\n 避坑：注意理解文中“take in”和“become aware of”的含义，它们都指向“获取/吸收信息”。题干设置了反向逻辑，将文中的“增强吸收能力”改成了“减弱吸收能力”。考生需要准确识别文中描述的压力反馈机制，即压力反而会让人对负面警示信息变得更加敏感而非迟钝。',11,1,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(39,3,39,4,'Stress created by social media posts can lead us to take unnecessary precautions.','[{\"label\": \"YES\"}, {\"label\": \"NO\"}, {\"label\": \"NOT GIVEN\"}]','\"YES\"','解题思路：定位到第11段末尾。文中描述了一个恶性循环：压力在人与人之间传播，增强了人们吸收负面信息的可能性，进而导致人们做出过度反应。文章给出了具体例子：即使灾难发生在地球另一端也会取消行程，或者在应该持有时卖出股票。这些在客观上并非必须、甚至有损利益的行为，正对应了题干中的“不必要的预防措施”（unnecessary precautions），信息一致，故答案为YES。\r\n 对应文章：第11段：After a stressful public event, ... ... And so, a reliable pattern emerges - stress is triggered, spreading from one person to the next, which temporarily enhances the likelihood that people will take in negative reports, which increases stress further. As a result, trips are cancelled, even if the disaster took place across the globe; stocks are sold, even when holding on is the best thing to do.\r\n 避坑：本题的难点在于对“unnecessary precautions”的同义替换理解。文中虽然没有直接出现这个词组，但通过“即使灾难在远方也取消行程”和“本该持有却卖出股票”这两个例子，暗示了这些行为是基于恐惧而非理性做出的过度防范。考生需要具备从具体案例中归纳抽象概念的能力。',11,3,'2026-03-17 23:07:13','2026-03-17 23:07:13',0),(40,3,40,4,'Our tendency to be affected by other people\'s moods can be used in a positive way.','[{\"label\": \"YES\"}, {\"label\": \"NO\"}, {\"label\": \"NOT GIVEN\"}]','\"YES\"','解题思路：定位到文章最后一段。作者在结尾处给出了积极的观点，指出积极情绪（如希望）同样具有传染性，并且能强有力地诱导人们采取行动寻找解决方案。末段首句提到的 positive emotions 会引诱人们采取行动找到解决方法，正对应了题干中“他人的情绪可被积极运用”的描述。最后一句进一步提到，意识到情绪状态与信息处理之间的紧密关系，可以帮助我们更有效地传达信息，成为积极的改变者。这证实了这种“受他人情绪影响”的心理倾向确实可以被正面、积极地利用，信息一致，故答案为YES。\r\n 对应文章：末段：The good news, however, is that positive emotions, such as hope, are contagious too, and are powerful in inducing people to act to find solutions.\r\n 避坑：考生可能会受前文大量关于压力、焦虑和负面影响的描述所误导，认为这种情绪传染倾向全是坏处。但雅思阅读文章往往在结尾处进行观点升华。看到“The good news”和“positive emotions”等词汇时，应敏锐察觉到作者论述方向的转变，从而准确匹配题干中的“positive way”。',12,0,'2026-03-17 23:07:13','2026-03-17 23:07:13',0);
/*!40000 ALTER TABLE `questions` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `topics`
--

DROP TABLE IF EXISTS `topics`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `topics` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '话题唯一ID',
  `code` varchar(30) NOT NULL COMMENT '话题编码（如technology/humanity）',
  `name` varchar(30) NOT NULL COMMENT '话题名称（如科技/人文）',
  `description` varchar(255) DEFAULT '' COMMENT '话题描述（可选）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_flag` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_code` (`code`) COMMENT '话题编码唯一（避免重复）',
  KEY `idx_name` (`name`) COMMENT '按话题名称筛选索引'
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='阅读文章话题分类表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `topics`
--

LOCK TABLES `topics` WRITE;
/*!40000 ALTER TABLE `topics` DISABLE KEYS */;
INSERT INTO `topics` VALUES (1,'technology','科技','','2026-03-17 21:45:32','2026-03-17 21:45:32',0),(2,'humanity','人文','','2026-03-17 21:45:32','2026-03-17 21:45:32',0),(3,'environment','环境','','2026-03-17 21:45:32','2026-03-17 21:45:32',0),(4,'health','健康','','2026-03-17 21:45:32','2026-03-17 21:45:32',0),(5,'language','语言','','2026-03-17 21:45:32','2026-03-17 21:45:32',0),(6,'animal','动物','','2026-03-17 21:45:32','2026-03-17 21:45:32',0);
/*!40000 ALTER TABLE `topics` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `user_answers`
--

DROP TABLE IF EXISTS `user_answers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user_answers` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '答题记录唯一ID',
